import{_ as a,o as i,c as e,ag as t}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"第 7 章：BM25 全文搜索","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/07-bm25-search.md","filePath":"chapters/07-bm25-search.md"}'),n={name:"chapters/07-bm25-search.md"};function d(h,s,l,p,r,o){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="第-7-章-bm25-全文搜索" tabindex="-1">第 7 章：BM25 全文搜索 <a class="header-anchor" href="#第-7-章-bm25-全文搜索" aria-label="Permalink to &quot;第 7 章：BM25 全文搜索&quot;">​</a></h1><blockquote><p>向量搜索擅长捕捉语义相似性，但当用户输入精确的函数名、错误代码或文件路径时，传统的全文搜索依然是最可靠的武器。qmd 基于 SQLite FTS5 构建了一套完整的 BM25 搜索管线，从自定义查询语法到分数归一化，每一层都有值得细读的设计。</p></blockquote><h2 id="fts5-虚拟表-搜索的基石" tabindex="-1">FTS5 虚拟表：搜索的基石 <a class="header-anchor" href="#fts5-虚拟表-搜索的基石" aria-label="Permalink to &quot;FTS5 虚拟表：搜索的基石&quot;">​</a></h2><p>qmd 在 SQLite 中创建了一张 FTS5 虚拟表来支撑全文索引（<code>src/store.ts</code> L738–742）：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 文件: src/store.ts L738-742</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VIRTUAL </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TABLE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> IF</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> NOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> EXISTS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> documents_fts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">USING</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fts5(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    filepath, title, body,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    tokenize</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;porter unicode61&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这张表索引了三个字段：<code>filepath</code>（文件路径）、<code>title</code>（标题）和 <code>body</code>（正文）。分词器的选择是 <code>porter unicode61</code>——这是两个分词器的组合。<code>unicode61</code> 负责按 Unicode 6.1 标准分割文本，正确处理非 ASCII 字符；<code>porter</code> 则在其上层应用 Porter 词干提取算法，将 &quot;running&quot;、&quot;runs&quot;、&quot;ran&quot; 统一还原为 &quot;run&quot;。</p><h3 id="为什么选择-porter-词干提取" tabindex="-1">为什么选择 Porter 词干提取？ <a class="header-anchor" href="#为什么选择-porter-词干提取" aria-label="Permalink to &quot;为什么选择 Porter 词干提取？&quot;">​</a></h3><p>Porter 算法是信息检索领域最经典的英文词干提取器。它通过一系列规则剥离后缀，使得同一词根的不同形态能够匹配。对于代码文档搜索来说，这意味着搜索 &quot;configure&quot; 也能命中包含 &quot;configuration&quot; 或 &quot;configured&quot; 的文档。代价是偶尔会产生过度归并（如 &quot;university&quot; 和 &quot;universal&quot; 可能被归为同一词干），但在技术文档场景下这种误差可以接受。</p><p><code>unicode61</code> 的加入确保了中文、日文等多字节字符不会被错误切分。虽然 Porter 算法本身只对英文有效，但 <code>unicode61</code> 保证了非英文内容至少能被正确索引和按字匹配。</p><h2 id="lex-查询语法" tabindex="-1">Lex 查询语法 <a class="header-anchor" href="#lex-查询语法" aria-label="Permalink to &quot;Lex 查询语法&quot;">​</a></h2><p>qmd 设计了一套简洁的查询语法（文档见 <code>docs/SYNTAX.md</code>），让用户能够精确控制搜索行为：</p><table tabindex="0"><thead><tr><th>语法</th><th>含义</th><th>转换为 FTS5</th></tr></thead><tbody><tr><td><code>term</code></td><td>前缀匹配</td><td><code>&quot;term&quot;*</code></td></tr><tr><td><code>&quot;exact phrase&quot;</code></td><td>精确短语</td><td><code>&quot;exact phrase&quot;</code></td></tr><tr><td><code>-term</code></td><td>排除</td><td><code>NOT &quot;term&quot;*</code></td></tr><tr><td><code>-&quot;phrase&quot;</code></td><td>排除短语</td><td><code>NOT &quot;phrase&quot;</code></td></tr></tbody></table><p>普通词项默认执行前缀匹配，这是一个深思熟虑的选择。用户输入 &quot;config&quot; 时，通常也希望命中 &quot;configuration&quot;、&quot;configure&quot; 等词。前缀匹配与 Porter 词干提取形成互补——Porter 处理后缀变化，前缀匹配处理用户输入不完整的情况。</p><p>双引号包裹的短语则执行精确匹配，不附加通配符。这让用户在需要精确搜索时有明确的手段。</p><h2 id="查询预处理" tabindex="-1">查询预处理 <a class="header-anchor" href="#查询预处理" aria-label="Permalink to &quot;查询预处理&quot;">​</a></h2><h3 id="sanitizefts5term" tabindex="-1">sanitizeFTS5Term <a class="header-anchor" href="#sanitizefts5term" aria-label="Permalink to &quot;sanitizeFTS5Term&quot;">​</a></h3><p><code>sanitizeFTS5Term()</code>（L2653–2655）是查询管线的第一道防线。它去除所有非单词字符并转为小写。这一步看似简单，实则至关重要——FTS5 的查询语法中有很多特殊字符（如 <code>*</code>、<code>+</code>、<code>:</code>），如果用户输入中包含这些字符且未被过滤，会导致查询解析失败甚至 SQL 注入风险。</p><h3 id="buildfts5query" tabindex="-1">buildFTS5Query <a class="header-anchor" href="#buildfts5query" aria-label="Permalink to &quot;buildFTS5Query&quot;">​</a></h3><p><code>buildFTS5Query()</code>（L2672–2738）是查询转换的核心。它将 Lex 语法解析为 FTS5 能理解的查询字符串。</p><p>函数内部维护两个数组：<code>positive[]</code> 存放正向匹配条件，<code>negative[]</code> 存放排除条件。解析过程逐字符扫描输入字符串：</p><p>遇到双引号时，提取引号内的完整短语，不添加前缀通配符。遇到减号时，将后续的词项或短语标记为负向。其余情况视为普通词项，清理后添加前缀通配符。</p><p>最终的 FTS5 查询按以下规则组装：正向条件之间用 <code>AND</code> 连接；如果存在负向条件，用 <code>NOT</code> 逐一追加。</p><p>这里有一个关键的边界情况处理：如果查询中只包含负向条件（例如 <code>-config</code>），函数返回 <code>null</code>。这是因为 FTS5 的 <code>NOT</code> 是二元运算符，它必须有一个左操作数。纯否定查询在 FTS5 中无法表达——你不能说&quot;给我所有不包含 config 的文档&quot;而不先指定一个正向条件。</p><h3 id="查询验证" tabindex="-1">查询验证 <a class="header-anchor" href="#查询验证" aria-label="Permalink to &quot;查询验证&quot;">​</a></h3><p><code>validateLexQuery()</code>（L2752–2761）检查查询字符串中是否包含换行符或未闭合的引号。换行符可能破坏 SQL 语句的结构，未闭合引号则会导致解析器进入错误状态。</p><p><code>validateSemanticQuery()</code>（L2744–2749）用于向量搜索和 HyDE 搜索模式。它拒绝包含否定语法的查询，因为向量相似度计算没有&quot;排除&quot;的概念——你无法在嵌入空间中表达&quot;远离这个向量&quot;。</p><h2 id="searchfts-主函数" tabindex="-1">searchFTS 主函数 <a class="header-anchor" href="#searchfts-主函数" aria-label="Permalink to &quot;searchFTS 主函数&quot;">​</a></h2><p><code>searchFTS()</code>（L2763–2814）是 BM25 搜索的入口。它编排了从查询解析到结果返回的完整流程。</p><h3 id="查询构建" tabindex="-1">查询构建 <a class="header-anchor" href="#查询构建" aria-label="Permalink to &quot;查询构建&quot;">​</a></h3><p>函数首先调用 <code>buildFTS5Query()</code> 将用户输入转换为 FTS5 查询。如果返回 <code>null</code>（纯否定查询），直接返回空结果。</p><h3 id="sql-查询与权重" tabindex="-1">SQL 查询与权重 <a class="header-anchor" href="#sql-查询与权重" aria-label="Permalink to &quot;SQL 查询与权重&quot;">​</a></h3><p>核心的 SQL 查询通过 JOIN 将 FTS5 虚拟表、文档元数据表和内容表关联起来：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ...</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> documents_fts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fts</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> documents </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> d </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> d</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filepath</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> fts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filepath</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> content </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> c </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> c</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filepath</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> d</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">filepath</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> documents_fts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">MATCH</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  AND</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> d</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">collection</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ?</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bm25(documents_fts, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ASC</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><code>bm25()</code> 函数的权重参数揭示了一个重要的设计决策：<code>filepath</code> 字段权重 10.0，<code>title</code> 字段权重 1.0，<code>body</code> 字段使用默认权重。</p><p>文件路径获得 10 倍加权，这背后的逻辑是：当用户搜索 &quot;store&quot; 时，名为 <code>store.ts</code> 的文件几乎一定是最相关的结果。路径匹配是极强的信号——用户往往记得文件名但不记得具体内容。标题次之，正文最低。这种加权方案在代码库搜索场景下非常合理。</p><p>集合过滤通过可选的 <code>WHERE d.collection = ?</code> 子句实现，允许用户将搜索范围限定在特定的文档集合内。</p><h3 id="分数归一化" tabindex="-1">分数归一化 <a class="header-anchor" href="#分数归一化" aria-label="Permalink to &quot;分数归一化&quot;">​</a></h3><p>BM25 算法返回的原始分数是负数（SQLite FTS5 的惯例），且数值范围不固定——取决于文档集合的大小、词频分布等因素。qmd 使用了一个优雅的归一化函数将其映射到 [0, 1) 区间：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>normalizedScore = |x| / (1 + |x|)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个函数有几个重要性质：</p><p>第一，它是单调递增的。BM25 原始分数的绝对值越大，归一化后的分数越高，排序不变。</p><p>第二，它的值域是 [0, 1)，永远不会达到 1。实际效果如下：</p><table tabindex="0"><thead><tr><th>BM25 原始分</th><th>归一化分数</th><th>匹配强度</th></tr></thead><tbody><tr><td>-10</td><td>0.91</td><td>强匹配</td></tr><tr><td>-2</td><td>0.67</td><td>中等匹配</td></tr><tr><td>-0.5</td><td>0.33</td><td>弱匹配</td></tr><tr><td>-0.1</td><td>0.09</td><td>极弱匹配</td></tr></tbody></table><p>第三，也是最关键的——它不依赖查询上下文。传统的 min-max 归一化需要知道当前查询结果中的最大和最小分数，这意味着不同查询之间的分数不可比较。而 <code>|x|/(1+|x|)</code> 是一个全局函数，任何查询、任何时间返回的分数都在同一尺度上。</p><h3 id="为什么跨模态可比性如此重要" tabindex="-1">为什么跨模态可比性如此重要？ <a class="header-anchor" href="#为什么跨模态可比性如此重要" aria-label="Permalink to &quot;为什么跨模态可比性如此重要？&quot;">​</a></h3><p>qmd 支持多种搜索模态：BM25 全文搜索、向量语义搜索、HyDE 搜索。在融合这些模态的结果时，需要对不同来源的分数进行加权合并。如果 BM25 返回的是 [-∞, 0] 区间的原始分数，而向量搜索返回 [0, 1] 的余弦相似度，两者根本无法直接比较。</p><p><code>|x|/(1+|x|)</code> 将 BM25 分数映射到与余弦相似度相同的 [0, 1) 区间，使得跨模态的分数融合变得简单而可靠。不需要每次查询都计算 min/max，不需要维护全局统计信息，只需要一个无状态的数学函数。</p><h2 id="查询语法的局限性" tabindex="-1">查询语法的局限性 <a class="header-anchor" href="#查询语法的局限性" aria-label="Permalink to &quot;查询语法的局限性&quot;">​</a></h2><p>当前的 Lex 语法有意保持简洁，但也因此存在一些限制。它不支持 OR 逻辑——所有正向条件都是 AND 关系。它不支持字段限定搜索（如 <code>title:config</code>）。它也不支持通配符的灵活放置（如 <code>*config*</code>）。</p><p>这些限制是有意为之的。qmd 面向的是代码文档搜索场景，用户通常输入的是关键词或函数名，复杂的布尔逻辑很少用到。保持语法简洁意味着更少的解析错误、更低的学习成本，以及更可预测的搜索行为。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>qmd 的 BM25 搜索系统展现了&quot;简洁但不简单&quot;的设计哲学。FTS5 虚拟表利用 Porter 词干提取和 Unicode61 分词器覆盖了多语言场景；Lex 查询语法在易用性和表达力之间找到了平衡点；<code>buildFTS5Query()</code> 正确处理了前缀匹配、短语搜索和否定查询的各种边界情况；路径字段的 10 倍加权体现了对代码库搜索场景的深刻理解；而 <code>|x|/(1+|x|)</code> 归一化函数则以极低的复杂度解决了跨模态分数可比性这一关键问题。整套系统没有使用任何外部搜索引擎依赖，仅凭 SQLite 内置的 FTS5 就实现了生产级的全文搜索能力。</p>`,52)])])}const u=a(n,[["render",d]]);export{k as __pageData,u as default};
